mapper.select:
select
    p.out_put_poll_id, p.execution_standard, p.first_date, p.check_frequency, p.plan_desc, p.submit_content, p.approval_opinion, p.status, p.create_time, p.update_time,
    o.out_put_id, o.out_put_name, o.out_put_type,
    op.pollutant_code, pc.pollutant_name_cn, pc.pollutant_name_en, op.over_maxValue, op.over_minValue
from t_env_manual_check_plan p
left join t_ent_output_pollutant op on op.out_put_poll_id = p.out_put_poll_id
left join t_bas_pollutant_code pc on pc.pollutant_code = op.pollutant_code
left join t_ent_out_put_info o on o.out_put_id = op.out_put_id



            and o.ent_code = #{entCode}



                and o.ent_code in

                    #{entCode}





        and o.out_put_id = #{outPutId}


        and p.status = #{status}


        and p.first_date between #{firstDateStart} and #{firstDateEnd}


order by o.out_put_id desc, p.first_date desc

mapper.update:
update t_env_manual_check_plan

    status = #{status}

        , execution_standard = #{executionStandard}, first_date = #{firstDate}, check_frequency = #{checkFrequency}, plan_desc = #{planDesc}


        , submit_content = #{submitContent}


        , approval_opinion = #{approvalOpinion}


where out_put_poll_id = #{outPutPollId}
